const {ethers, ethers:{utils:{parseEther, formatEther}}} = require('ethers')
const { abi: abiUtil, bytecode: bytecodeUtil } = require('../contracts/build/contracts/UtilImpl.json');

// deploy announcement, scan utils on evm.
async function main() {
    const [, , pk, url] = process.argv;
    console.log(`rpc url [${url}]`)
    const provider = ethers.getDefaultProvider(url)
    const {chainId} = await provider.getNetwork();
    const signer = new ethers.Wallet(pk, provider);
    const account = await signer.getAddress();
    const balance = await signer.getBalance()
    console.log(`network ${chainId} account ${account} balance ${formatEther(balance)}`);
    if (BigInt(balance) === BigInt(0)) {
        console.log(`insufficient balance`)
        return;
    }
    await deployAnnouncer(signer);

    console.log()
    await deploy(signer, 'scan util', bytecodeUtil)
}
async function deployAnnouncer(signer) {
    const {contractAddress, transactionHash} = await signer.sendTransaction({data: ''})
        .then(tx=>tx.wait())
    console.log(`deploy announcement ok, transactionHash ${transactionHash
    } \n contractAddress `, contractAddress)
}

async function deploy(signer, name, bytecode, args=[]) {
    const factory = new ethers.ContractFactory([], bytecode, signer)
    const cd = await factory.deploy(...args);
    const dd = await cd.deployed();
    console.log(`deploy ${name} at ${cd.address} , tx hash ${dd.deployTransaction?.hash}`)
    return cd
}

if (module === require.main) {
    main()
        .then(() => {
            console.log(`Task finished.`)
            process.exit(0)
        })
        .catch((error) => {
            console.error('Error in main', error);
            process.exit(1);
        });
}